import { execSync } from "child_process";

function gws(args: string, jsonParams?: object, jsonBody?: object): any {
  let cmd = `gws ${args}`;
  if (jsonParams) {
    cmd += ` --params "${JSON.stringify(jsonParams).replace(/"/g, '\\"')}"`;
  }
  if (jsonBody) {
    cmd += ` --json "${JSON.stringify(jsonBody).replace(/"/g, '\\"')}"`;
  }
  const output = execSync(cmd, { encoding: "utf-8", shell: "cmd.exe" });
  return JSON.parse(output);
}

const THREAD_ID = "19cf0302ebf905a6";

// Get full thread with metadata format to see headers
const threadData = gws("gmail users threads get", { userId: "me", id: THREAD_ID, format: "metadata", metadataHeaders: ["Subject", "From", "To", "Cc", "Date"] });

const messages = threadData.messages || [];
console.log(`Total messages: ${messages.length}`);

const participants = new Set<string>();
let subject = "";

for (const msg of messages) {
  const headers = msg.payload?.headers || [];
  const getHeader = (name: string) => headers.find((h: any) => h.name.toLowerCase() === name.toLowerCase())?.value || "";

  const msgSubject = getHeader("Subject");
  if (!subject && msgSubject) subject = msgSubject;

  const from = getHeader("From");
  const to = getHeader("To");
  const cc = getHeader("Cc");

  console.log(`\nMessage ID: ${msg.id}`);
  console.log(`  Subject: ${msgSubject}`);
  console.log(`  From: ${from}`);
  console.log(`  To: ${to}`);
  console.log(`  CC: ${cc}`);
  console.log(`  Date: ${getHeader("Date")}`);

  // Extract emails
  const extractEmails = (str: string) => {
    const matches = str.match(/[\w.+-]+@[\w.-]+\.\w+/g) || [];
    matches.forEach(e => participants.add(e.toLowerCase()));
  };
  extractEmails(from);
  extractEmails(to);
  extractEmails(cc);
}

console.log(`\nSubject: ${subject}`);
console.log(`Participants (${participants.size}):`, [...participants]);

import { execSync } from "child_process";

function gws(args: string, jsonParams?: object, jsonBody?: object): any {
  let cmd = `gws ${args}`;
  if (jsonParams) {
    cmd += ` --params "${JSON.stringify(jsonParams).replace(/"/g, '\\"')}"`;
  }
  if (jsonBody) {
    cmd += ` --json "${JSON.stringify(jsonBody).replace(/"/g, '\\"')}"`;
  }
  const output = execSync(cmd, { encoding: "utf-8", shell: "cmd.exe" });
  return JSON.parse(output);
}

function decodeBase64(str: string): string {
  // Gmail uses URL-safe base64
  const b64 = str.replace(/-/g, '+').replace(/_/g, '/');
  return Buffer.from(b64, 'base64').toString('utf-8');
}

function extractText(payload: any): string {
  if (!payload) return "";

  if (payload.body?.data) {
    return decodeBase64(payload.body.data);
  }

  if (payload.parts) {
    for (const part of payload.parts) {
      if (part.mimeType === 'text/plain' && part.body?.data) {
        return decodeBase64(part.body.data);
      }
    }
    // Try HTML if no plain text
    for (const part of payload.parts) {
      if (part.mimeType === 'text/html' && part.body?.data) {
        const html = decodeBase64(part.body.data);
        // strip tags roughly
        return html.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
      }
      // Recurse into nested parts
      if (part.parts) {
        const text = extractText(part);
        if (text) return text;
      }
    }
  }
  return "";
}

const THREAD_ID = "19cf0302ebf905a6";

// Get full thread
const threadData = gws("gmail users threads get", { userId: "me", id: THREAD_ID, format: "full" });

const messages = threadData.messages || [];
console.log(`Total messages: ${messages.length}`);

for (const msg of messages) {
  const headers = msg.payload?.headers || [];
  const getHeader = (name: string) => headers.find((h: any) => h.name.toLowerCase() === name.toLowerCase())?.value || "";

  console.log(`\n${'='.repeat(60)}`);
  console.log(`Message: ${msg.id}`);
  console.log(`Subject: ${getHeader("Subject")}`);
  console.log(`From: ${getHeader("From")}`);
  console.log(`Date: ${getHeader("Date")}`);

  const text = extractText(msg.payload);
  console.log(`\n--- Body (first 2000 chars) ---`);
  console.log(text.substring(0, 2000));
}

